# 延迟计算描述符
class LazyProperty:
    def __init__(self, func):
        self.func = func

    def __get__(self, obj, objtype=None):
        if obj is None: return self
        value = self.func(obj)
        setattr(obj, self.func.__name__, value)  # 缓存到实例
        return value

