# 迭代协议（鸭子类型经典例子）
class MyRange:
    def __init__(self, n):
        self.n = n
        self.i = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.i >= self.n:
            raise StopIteration
        val = self.i
        self.i += 1
        return val

# 不需要继承任何接口，只要有__iter__和__next__就能迭代
for i in MyRange(5):
    print(i)  # 0 1 2 3 4

from typing import TypeVar, Generic, Protocol, Union, Optional, Callable, List, Dict

# TypeVar - 泛型变量
T = TypeVar('T')
K = TypeVar('K')
V = TypeVar('V')

def first(items: List[T]) -> Optional[T]:
    return items[0] if items else None

# Generic - 自定义泛型
class Stack(Generic[T]):
    def __init__(self) -> None:
        self._items: List[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> Optional[T]:
        return self._items.pop() if self._items else None

# Protocol - 结构子类型
class Drawable(Protocol):
    def draw(self) -> None: ...

def render(item: Drawable) -> None:
